import React, { useState, useEffect } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { Plus, Search, Trash2, ChevronRight, ChevronLeft, FileDown, Globe } from 'lucide-react';
import { getPresupuestos, deletePresupuesto, updatePresupuesto, convertirAOrden, getPresupuestoPdf, enviarPresupuestoWhatsApp, enviarPresupuestoEmail } from '../../services/api';
import { formatCurrency, formatDate, badgeClass, estadosPresupuestoLocal } from '../../utils/formatters';
import ConfirmDialog from '../common/ConfirmDialog';
import Loading from '../common/Loading';

export default function PresupuestosList() {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [estado, setEstado] = useState(searchParams.get('estado') || '');
  const [deleteId, setDeleteId] = useState(null);

  const load = () => {
    setLoading(true);
    getPresupuestos({ search: search || undefined, estado: estado || undefined }).then((res) => {
      setData(res.data);
      setLoading(false);
    });
  };

  // eslint-disable-next-line react-hooks/exhaustive-deps
  useEffect(() => { load(); }, [search, estado]);

  const handleDelete = async () => {
    if (!deleteId) return;
    await deletePresupuesto(deleteId);
    setDeleteId(null);
    load();
  };

  const avanzarEstado = async (p) => {
    const idx = estadosPresupuestoLocal.indexOf(p.estado);
    if (idx < estadosPresupuestoLocal.length - 1) {
      await updatePresupuesto(p.id, { estado: estadosPresupuestoLocal[idx + 1] });
      load();
    }
  };

  const retrocederEstado = async (p) => {
    const idx = estadosPresupuestoLocal.indexOf(p.estado);
    if (idx > 0) {
      await updatePresupuesto(p.id, { estado: estadosPresupuestoLocal[idx - 1] });
      load();
    }
  };

  const handleConvertir = async (id) => {
    if (!window.confirm('¿Convertir este presupuesto en orden de trabajo?')) return;
    try {
      await convertirAOrden(id);
      load();
    } catch (err) {
      alert(err.response?.data?.detail || 'Error al convertir');
    }
  };

  const handleEnviarWhatsApp = async (id) => {
    try {
      await enviarPresupuestoWhatsApp(id);
      alert('WhatsApp enviado correctamente');
    } catch (err) {
      alert(err.response?.data?.detail || 'Error al enviar WhatsApp');
    }
  };

  const handleEnviarEmail = async (id) => {
    try {
      await enviarPresupuestoEmail(id);
      alert('Email enviado correctamente');
    } catch (err) {
      alert(err.response?.data?.detail || 'Error al enviar email');
    }
  };

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
        <h1 style={{ fontSize: 24, fontWeight: 700 }}>PRESUPUESTOS LOCAL</h1>
        <div style={{ display: 'flex', gap: 8 }}>
          <button className="btn btn-outline" onClick={() => navigate('/presupuestos-online')}>
            <Globe size={16} /> PRESUPUESTOS EN LÍNEA
          </button>
          <button className="btn btn-primary" onClick={() => navigate('/presupuestos/nuevo')}>
            <Plus size={16} /> Nuevo Presupuesto Local
          </button>
        </div>
      </div>

      <div className="card" style={{ marginBottom: 16 }}>
        <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
          <div style={{ position: 'relative', flex: 1, minWidth: 250 }}>
            <Search size={18} style={{ position: 'absolute', left: 12, top: '50%', transform: 'translateY(-50%)', color: '#94a3b8' }} />
            <input className="input" placeholder="Buscar por número o cliente..." value={search} onChange={(e) => setSearch(e.target.value)} style={{ paddingLeft: 40 }} />
          </div>
          <select className="input" style={{ width: 220 }} value={estado} onChange={(e) => setEstado(e.target.value)}>
            <option value="">Todos los estados</option>
            {estadosPresupuestoLocal.map((e) => <option key={e} value={e}>{e}</option>)}
          </select>
        </div>
      </div>

      {loading ? <Loading /> : (
        <div className="card">
          <div className="table-container">
            <table>
              <thead>
                <tr>
                  <th>Número</th>
                  <th>Cliente</th>
                  <th>Estado</th>
                  <th>Total ARS</th>
                  <th>Total USD</th>
                  <th>Seña</th>
                  <th>Saldo</th>
                  <th style={{ width: 160 }}>Acciones</th>
                </tr>
              </thead>
              <tbody>
                {data.map((p) => (
                  <tr key={p.id} style={{ cursor: 'pointer' }} onClick={() => navigate(`/presupuestos/${p.id}`)}>
                    <td style={{ fontWeight: 600, fontFamily: 'monospace' }}>{p.numero}</td>
                    <td>{p.cliente_nombre || '-'}</td>
                    <td><span className={badgeClass(p.estado)}>{p.estado}</span></td>
                    <td style={{ fontWeight: 600 }}>{formatCurrency(p.total)}</td>
                    <td style={{ fontWeight: 600, color: '#059669' }}>
                      USD {(p.total_usd || 0).toLocaleString('es-AR', { minimumFractionDigits: 2 })}
                    </td>
                    <td>{formatCurrency(p.sena_recibida)}</td>
                    <td style={{ fontWeight: 600 }}>{formatCurrency(p.saldo_pendiente)}</td>
                    <td onClick={(e) => e.stopPropagation()}>
                      <div style={{ display: 'flex', gap: 4, flexWrap: 'wrap' }}>
                        {p.estado !== estadosPresupuestoLocal[0] && (
                          <button className="btn btn-outline" style={{ padding: '4px 6px' }} onClick={() => retrocederEstado(p)} title="Retroceder estado">
                            <ChevronLeft size={14} />
                          </button>
                        )}
                        {p.estado !== estadosPresupuestoLocal[estadosPresupuestoLocal.length - 1] && (
                          <button className="btn btn-outline" style={{ padding: '4px 6px' }} onClick={() => avanzarEstado(p)} title="Avanzar estado">
                            <ChevronRight size={14} />
                          </button>
                        )}
                        <button className="btn btn-outline" style={{ padding: '4px 6px' }} onClick={() => window.open(getPresupuestoPdf(p.id), '_blank')} title="Descargar PDF">
                          <FileDown size={14} />
                        </button>
                        <button className="btn btn-success" style={{ padding: '4px 6px' }} onClick={() => handleEnviarWhatsApp(p.id)} title="WhatsApp">
                          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.38 8.38 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8v.5z"/></svg>
                        </button>
                        <button className="btn btn-outline" style={{ padding: '4px 6px' }} onClick={() => handleEnviarEmail(p.id)} title="Email">
                          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z"/><polyline points="22,6 12,13 2,6"/></svg>
                        </button>
                        <button className="btn btn-danger" style={{ padding: '4px 6px' }} onClick={() => setDeleteId(p.id)}>
                          <Trash2 size={14} />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
                {data.length === 0 && (
                  <tr><td colSpan={8} style={{ textAlign: 'center', padding: 40, color: '#94a3b8' }}>No hay presupuestos locales</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}

      <ConfirmDialog isOpen={!!deleteId} onClose={() => setDeleteId(null)} onConfirm={handleDelete} title="Eliminar presupuesto" message="¿Estás seguro?" />
    </div>
  );
}
